    "force": {"valeur": 15, "modificateur": 2},
    "dextérité": {"valeur": 10, "modificateur": 0},
    "constitution": {"valeur": 14, "modificateur": 2},
    "intelligence": {"valeur": 8, "modificateur": -1},
